const { createApp } = require('zero-http')
const app = createApp()

const clients = new Set()

app.ws('/chat', {
	maxPayload: 64 * 1024,
	pingInterval: 20000,
	verifyClient: (req) => req.headers['x-api-key'] === 'secret'
}, (ws, req) => {
	clients.add(ws)
	ws.data.name = req.query.name || 'anon'
	ws.send('Welcome, ' + ws.data.name + '!')

	ws.on('message', msg => {
		for (const c of clients) {
			if (c !== ws && c.readyState === 1)
				c.send(ws.data.name + ': ' + msg)
		}
	})

	ws.on('close', () => clients.delete(ws))
})

app.listen(3000)

// Properties available on each ws connection:
app.ws('/demo', (ws, req) => {
	console.log(ws.id)             // 'ws_1_a3x9k'
	console.log(ws.readyState)     // 1 (OPEN)
	console.log(ws.protocol)       // negotiated sub-protocol
	console.log(ws.headers)        // upgrade request headers
	console.log(ws.ip)             // remote IP
	console.log(ws.query)          // parsed query params
	console.log(ws.url)            // upgrade URL
	console.log(ws.secure)         // true for wss://
	console.log(ws.connectedAt)    // timestamp of connection
	console.log(ws.uptime)         // ms since connected
	console.log(ws.bufferedAmount) // pending bytes

	// Per-connection data store
	ws.data.role = 'admin'
	if (ws.data.role === 'admin') ws.send('admin tools unlocked')

	// State constants
	if (ws.readyState === WebSocketConnection.OPEN) { /* connected */ }
})

const { createApp, WebSocketPool } = require('zero-http')
const app = createApp()
const pool = new WebSocketPool()

app.ws('/chat', (ws, req) => {
	pool.add(ws)                      // auto-removed on close
	pool.join(ws, req.query.room || 'general')

	ws.data.name = req.query.name || 'anon'
	pool.toRoomJSON('general', { type: 'join', user: ws.data.name }, ws)

	ws.on('message', msg => {
		const room = pool.roomsOf(ws)[0]
		pool.toRoom(room, ws.data.name + ': ' + msg, ws)
	})

	ws.on('close', () => {
		console.log('pool size:', pool.size)
		console.log('rooms:', pool.rooms)
	})
})

// Broadcast to everyone
app.get('/announce', (req, res) => {
	pool.broadcastJSON({ announcement: req.query.msg })
	res.json({ sent: pool.size })
})

app.listen(3000)

app.get('/events', (req, res) => {
	const sse = res.sse({
		status: 200,
		retry: 5000,
		keepAlive: 30000,
		keepAliveComment: 'ping',
		autoId: true,
		startId: 1,
		pad: 2048,
		headers: { 'X-Stream': 'live' }
	})

	// Send unnamed data event
	sse.send('hello')

	// Send named event with object data
	sse.event('update', { x: 1, y: 2 })

	// Props
	console.log(sse.connected)   // true
	console.log(sse.eventCount)  // 2
	console.log(sse.bytesSent)   // bytes written
	console.log(sse.uptime)      // ms since opened
	console.log(sse.secure)      // true for HTTPS
	console.log(sse.data)        // {} user store

	// Periodic events
	const iv = setInterval(() => sse.event('tick', Date.now()), 1000)
	sse.on('close', () => clearInterval(iv))
})

