const { Database, Model, TYPES } = require('zero-http')

// Define a model
class User extends Model {
	static table = 'users'
	static timestamps = true    // adds createdAt, updatedAt
	static softDelete = true    // adds deletedAt, enables restore()
	static schema = {
		id:    { type: TYPES.INTEGER, primaryKey: true, autoIncrement: true },
		name:  { type: TYPES.STRING, required: true, minLength: 2 },
		email: { type: TYPES.STRING, required: true, unique: true },
		age:   { type: TYPES.INTEGER, min: 0, max: 150 },
		role:  { type: TYPES.STRING, enum: ['user', 'admin'], default: 'user' },
		meta:  { type: TYPES.JSON, default: {} }
	}
	static hooks = {
		beforeCreate: (data) => { data.email = data.email.toLowerCase() },
		afterCreate: (instance) => console.log('Created:', instance.id)
	}
}

// Connect and sync
const db = Database.connect('memory')
db.register(User)
await db.sync()

// CRUD
const user = await User.create({ name: 'Alice', email: 'alice@test.com', age: 30 })
const found = await User.findById(user.id)
await found.update({ age: 31 })
await found.delete()    // soft-delete (sets deletedAt)
await found.restore()   // undo soft-delete

// Query builder
